#!/usr/bin/env python3
"""
Split subreads BAM by query_name parity.

For reads whose query_name ends with an even digit: output unchanged.
For reads whose query_name ends with an odd digit: reverse complement the
sequence, reverse CIGAR, reverse per-base aux fields, flip strand bit.
"""

import argparse
import array
import sys
import pysam
from tqdm import tqdm


def reverse_complement(seq: str) -> str:
    """Return the reverse complement of a DNA string."""
    comp = str.maketrans("ACGTacgtnN", "TGCAtgcnaN")
    return seq.translate(comp)[::-1]


def identify_perbase_tags(tags, query_length: int):
    """Return dict of {tag_name: raw_value} for array fields whose length == query_length."""
    perbase = {}
    for name, value in tags:
        if isinstance(value, str):
            continue  # string tags (e.g. RG)
        if isinstance(value, (int, float)):
            continue  # scalar
        if isinstance(value, array.array) and len(value) == query_length:
            perbase[name] = value
        elif isinstance(value, (list, tuple)) and len(value) == query_length:
            perbase[name] = value
    return perbase


def reverse_read(read: pysam.AlignedSegment) -> pysam.AlignedSegment:
    """Reverse complement a single read in-place and return it."""
    seq = read.query_sequence
    if seq is None:
        return read

    read.query_sequence = reverse_complement(seq)

    # Reverse base qualities
    if read.qual is not None:
        read.qual = read.qual[::-1]

    # Reverse CIGAR
    if read.cigartuples:
        cigar = pysam.Cigar.from_cigartuple(read.cigartuples)
        read.cigartuples = tuple(cigar[::-1])

    # Identify and reverse per-base aux fields
    perbase_tags = identify_perbase_tags(read.tags, read.query_length)

    for tag_name, value in perbase_tags.items():
        if isinstance(value, array.array):
            code = value.typecode
            reversed_val = array.array(code, reversed(value))
        elif isinstance(value, bytes):
            reversed_val = bytes(reversed(value))
        elif isinstance(value, bytearray):
            reversed_val = bytearray(reversed(value))
        elif isinstance(value, (list, tuple)):
            reversed_val = list(reversed(value))
        else:
            continue
        read.set_tag(tag_name, reversed_val)

    return read


def split_by_polarity(input_bam: str, output_bam: str, threads: int = 40):
    """Split subreads BAM by query_name last-digit parity."""
    with pysam.AlignmentFile(input_bam, "rb", threads=threads, check_sq=False) as in_bam:
        with pysam.AlignmentFile(
            output_bam, "wb", header=in_bam.header, threads=threads, check_sq=False
        ) as out_bam:

            count_even = 0
            count_odd = 0

            for read in tqdm(in_bam.fetch(until_eof=True), desc=f"processing {input_bam}"):
                qname = read.query_name
                idx = int(qname.split("/")[-1])

                if idx % 2 == 0:
                    out_bam.write(read)
                    count_even += 1
                else:
                    read = reverse_read(read)
                    out_bam.write(read)
                    count_odd += 1

    print(f"Done. even={count_even}, odd={count_odd}, total={count_even + count_odd}")


def main_cli():
    parser = argparse.ArgumentParser(
        description="Split subreads BAM by query_name parity (even/odd)."
    )
    parser.add_argument("input_bam", help="Input subreads BAM file")
    parser.add_argument("output_bam", help="Output BAM file path")

    if len(sys.argv) == 1:
        parser.print_help(sys.stderr)
        sys.exit(1)

    args = parser.parse_args()
    split_by_polarity(args.input_bam, args.output_bam)


if __name__ == "__main__":
    main_cli()


